mapper.select:
select hvo.id, hvo.voucher_id, hvo.order_id, hvo.order_no, hvo.status, hv.name as voucher_name, hv.scope_type, hv.channel_type as scope_label, hv.pay_value as threshold_amount, hv.actual_value as discount_amount, hvo.receive_time, hvo.use_time, hvo.expire_time from hotel_high_voucher_order hvo inner join hotel_high_voucher hv on hv.id = hvo.voucher_id where hvo.user_id = #{userId}
and hvo.status = #{status}
order by hvo.receive_time desc

mapper.update:
update hotel_high_voucher_order
order_id = #{orderId}, status = #{status}, lock_time = #{lockTime}, use_time = #{useTime}, cancel_time = #{cancelTime},
where id = #{id}
